          'description' => 'Latitude in decimal degrees (default: 41.0, off New England coast).',
        ),
        'longitude' => 
        array (
          'type' => 'number',
          'description' => 'Longitude in decimal degrees (default: -71.0).',
        ),
        'city' => 
        array (
          'type' => 'string',
          'description' => 'Coastal city name — auto-geocodes to lat/lon.',
        ),
        'timeout' => 
        array (
          'type' => 'integer',
