if (! function_exists('marine_weather')) {
    function marine_weather($latitude = null, $longitude = null, $city = null, $timeout = null)
    {
        $latitude = (float)($latitude ?? 41.0);
        $longitude = (float)($longitude ?? -71.0);
        $timeout = (int)($timeout ?? 15);
        $city = $city ?? '';

        // Geocode city if provided
        if (!empty($city)) {
            $geo_url = 'https://geocoding-api.open-meteo.com/v1/search?name=' . urlencode($city) . '&count=1&format=json';
            $geo_ctx = stream_context_create([
                'http' => ['method' => 'GET', 'timeout' => 10, 'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/json\r\n", 'ignore_errors' => true]
            ]);
            $geo_resp = @file_get_contents($geo_url, false, $geo_ctx);
            if ($geo_resp !== false) {
                $geo_data = json_decode($geo_resp, true);
                if (isset($geo_data['results'][0])) {
                    $latitude = (float)$geo_data['results'][0]['latitude'];
                    $longitude = (float)$geo_data['results'][0]['longitude'];
                    $city_name = $geo_data['results'][0]['name'] . ', ' . ($geo_data['results'][0]['country'] ?? '');
                }
            }
        }

        // Open-Meteo Marine API — free, no key
        $marine_params = [
            'wave_height',           // Significant wave height (m)
            'wave_direction',        // Mean wave direction (°)
            'wave_period',           // Mean wave period (s)
            'wind_wave_height',      // Wind wave height (m)
            'wind_wave_direction',   // Wind wave direction (°)
            'wind_wave_period',      // Wind wave period (s)
            'swell_wave_height',     // Swell wave height (m)
            'swell_wave_direction',  // Swell wave direction (°)
            'swell_wave_period',     // Swell wave period (s)
            'ocean_current_velocity', // Ocean current velocity (m/s)
            'ocean_current_direction', // Ocean current direction (°)
            'sea_surface_temperature', // Sea surface temperature (°C)
        ];

        $url = 'https://marine-api.open-meteo.com/v1/marine'
            . '?latitude=' . $latitude
            . '&longitude=' . $longitude
            . '&hourly=' . implode(',', $marine_params)
            . '&timezone=auto'
            . '&forecast_days=2';

        $context = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/json\r\n",
                'ignore_errors' => true,
            ]
        ]);

        $response = @file_get_contents($url, false, $context);

        if ($response === false) {
            return ['success' => false, 'error' => 'Failed to reach Open-Meteo Marine API.'];
        }

        $data = json_decode($response, true);

        if ($data === null) {
            return ['success' => false, 'error' => 'Failed to parse API response.'];
        }

        if (isset($data['error'])) {
            return ['success' => false, 'error' => 'API error: ' . ($data['reason'] ?? 'Unknown')];
        }

        $hourly = $data['hourly'] ?? [];
        $times = $hourly['time'] ?? [];

        // Compute current conditions (first hour)
        $current = [];
        if (!empty($times)) {
            $current = [
                'time' => $times[0],
                'wave_height_m' => $hourly['wave_height'][0] ?? null,
                'wave_direction_deg' => $hourly['wave_direction'][0] ?? null,
                'wave_period_s' => $hourly['wave_period'][0] ?? null,
                'wind_wave_height_m' => $hourly['wind_wave_height'][0] ?? null,
                'swell_wave_height_m' => $hourly['swell_wave_height'][0] ?? null,
                'swell_wave_direction_deg' => $hourly['swell_wave_direction'][0] ?? null,
                'swell_wave_period_s' => $hourly['swell_wave_period'][0] ?? null,
                'ocean_current_velocity_ms' => $hourly['ocean_current_velocity'][0] ?? null,
                'ocean_current_direction_deg' => $hourly['ocean_current_direction'][0] ?? null,
                'sea_surface_temperature_c' => $hourly['sea_surface_temperature'][0] ?? null,
            ];
        }

        // Compute daily averages
        $daily = [];
        if (!empty($times)) {
            $day_groups = [];
            foreach ($times as $i => $t) {
                $day = substr($t, 0, 10);
                $day_groups[$day][] = $i;
            }
            
            foreach ($day_groups as $day => $indices) {
                $avg = fn($field) => $indices ? round(array_sum(array_map(fn($i) => $hourly[$field][$i] ?? 0, $indices)) / count($indices), 2) : null;
                $max = fn($field) => $indices ? round(max(array_map(fn($i) => $hourly[$field][$i] ?? 0, $indices)), 2) : null;
                
                $daily[] = [
                    'date' => $day,
                    'avg_wave_height_m' => $avg('wave_height'),
                    'max_wave_height_m' => $max('wave_height'),
                    'avg_wave_period_s' => $avg('wave_period'),
                    'avg_swell_height_m' => $avg('swell_wave_height'),
                    'max_swell_height_m' => $max('swell_wave_height'),
                    'avg_sea_temp_c' => $avg('sea_surface_temperature'),
                ];
            }
        }

        // Wave description
        $wave_desc = 'calm';
        $wh = $current['wave_height_m'] ?? 0;
        if ($wh === null) $wave_desc = 'unknown';
        elseif ($wh < 0.3) $wave_desc = 'calm (rippled)';
        elseif ($wh < 1.0) $wave_desc = 'smooth';
        elseif ($wh < 2.0) $wave_desc = 'slight to moderate';
        elseif ($wh < 3.0) $wave_desc = 'moderate to rough';
        elseif ($wh < 5.0) $wave_desc = 'rough to very rough';
        elseif ($wh < 9.0) $wave_desc = 'high to very high';
        else $wave_desc = 'phenomenal';

        // Swell description
        $swell_desc = 'none';
        $sh = $current['swell_wave_height_m'] ?? 0;
        if ($sh === null) $swell_desc = 'unknown';
        elseif ($sh < 0.5) $swell_desc = 'low';
        elseif ($sh < 2.0) $swell_desc = 'moderate';
        elseif ($sh < 4.0) $swell_desc = 'heavy';
        else $swell_desc = 'very heavy';

        return [
            'success' => true,
            'location' => [
                'name' => $city_name ?? null,
                'latitude' => $latitude,
                'longitude' => $longitude,
            ],
            'units' => $data['hourly_units'] ?? [],
            'current_conditions' => $current,
            'descriptions' => [
                'wave' => $wave_desc,
                'swell' => $swell_desc,
            ],
            'daily_summary' => $daily,
            'forecast_hours' => count($times),
        ];
    }
}
